def logo_url_for(symbol: str) -> str | None:
    """Absolute URL to a stock's logo served by this backend, or None if unknown."""
    fname = LOGO_FILES.get((symbol or "").upper())
    if not fname:
        return None
    return f"{settings.BACKEND_URL.rstrip(chr(47))}/logos/{fname}"
